#!/usr/bin/env bash
# ai-ui-prompt-to-ui.sh — AI 生成 → 设计师精炼 UI（prompt-to-UI） SOP walkthrough for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
WORKFLOW="AI 生成 → 设计师精炼 UI（prompt-to-UI）"

usage() {
  cat <<EOF
ai-ui-prompt-to-ui.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./ai-ui-prompt-to-ui.sh             # interactive
  ./ai-ui-prompt-to-ui.sh --dry-run
  ./ai-ui-prompt-to-ui.sh --json
  ./ai-ui-prompt-to-ui.sh --explain
  ./ai-ui-prompt-to-ui.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "AI 生成 → 设计师精炼 UI（prompt-to-UI）" 工作流。

一句话: 从「一句话需求 / 草图」到「可点的高保真 UI（或可用前端代码骨架）」，用 AI 起草、设计师做品味与系统对齐的精炼。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**写 prompt（描述意图）**: 描述屏幕、内容、状态、风格约束。跳过/写糊→生成出通用 AI 味、不贴需求的界面。 (evidence: [T03-S018])"
  "**生成（Figma Make / v0）**: AI 出可交互 UI / 代码；Figma Make 在画布上原生生成可编辑 frame，v0 出 React+Tailwind。跳过→回到从零手画，慢。 (evidence: [T03-S018, T03-S019])"
  "**筛选方向**: 从多个生成结果挑一个可用骨架。跳过→在烂骨架上死磕，不如重 prompt。 (evidence: [T03-S018])"
  "**导入 + 精炼（设计师 craft）**: 接进 Figma，套设计系统 token、调字体/间距/网格、规范组件复用。跳过→AI 草稿停在「能看不能用」，不一致、不可维护。 (evidence: [T03-S018])"
  "**验证 + 交付**: 走可用性/系统一致性检查后交付。跳过→把 AI 幻觉的交互/无障碍坑直接带进产品。 (evidence: [T03-S015])"
)
declare -a FAILURE_MODES=(
  "把 AI 草稿当成品 ship: 生成的界面有通用 AI 味、不一致、无障碍坑。**用 AI 起草，但留出半天做 token 对齐 + 无障碍 + craft 精炼，否则技术债转移到工程。** (evidence: [T03-S018, T03-S015])"
  "AI 自造一套设计语言: 生成结果不复用现有 token/组件，破坏一致性。**生成后第一步就映射到现有设计系统，别让 AI 平行造轮子。** (evidence: [T03-S013, T03-S018])"
  "prompt 太糊: 没给状态/约束/内容，得到占位 lorem 界面。**prompt 写明真实内容、空/错/加载态与品牌约束。** (evidence: [T03-S018])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "ai-ui-prompt-to-ui-walkthrough"
fi
